#include <bits/stdc++.h>
using namespace std;

int par[100001];
int find(int x){ return par[x]==x?x:par[x]=find(par[x]); }

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n, m; cin >> n >> m;
    for(int i=1;i<=n;i++) par[i]=i;
    int ans=0;
    for(int i=1;i<=m;i++){
        int u,v; cin >> u >> v;
        if(ans!=0) continue;
        int ru=find(u), rv=find(v);
        if(ru==rv){ ans=i; }
        else par[ru]=rv;
    }
    cout << ans << "\n";
    return 0;
}
